import os, sys, io, csv, zipfile, re, tempfile
import xml.etree.ElementTree as ET
from datetime import datetime, timedelta
from flask import Flask, request, send_file, jsonify


# ═══════════════════════════════════════════════════════════════
# MÓDULO: Excel → Asana CSV
# ═══════════════════════════════════════════════════════════════
import sys, os, csv, zipfile, xml.etree.ElementTree as ET

# ── Columnas del CSV de Asana (en orden exacto) ───────────────────────────────
ASANA_COLUMNS = [
    "Task ID", "Created At", "Completed At", "Last Modified", "Name",
    "Section/Column", "Assignee", "Assignee Email", "Start Date", "Due Date",
    "Tags", "Notes", "Projects", "Parent task",
    "Blocked By (Dependencies)", "Blocking (Dependencies)",
    "Type of Task", "Start Plan Date", "End Plan Date",
    "Current Delay.", "Final delay", "Status for Task",
    "Priority 1206192404054526_1199683667670284",
    "Earned Value (EV)", "PV", "SPI", "Deliverable Status",
    "% Impact", "% Ocurrence",
    "Workstream CT", "Company CT", "Functional Areas CT",
    "hasStarted", "Next EV Check", "Next PV Check", "Assignee Email.1",
]

# ── Cabeceras de columna reconocidas (variantes posibles) ─────────────────────
HEADER_ALIASES = {
    "name":       ["task name", "task name(*)", "nombre de tarea"],
    "type":       ["type", "type(*)", "tipo"],
    "status":     ["status", "status (*)", "estado"],
    "assignee":   ["assignee", "assignee(*)", "asignado"],
    "start_plan": ["start plan date", "start plan date(*)", "fecha inicio plan"],
    "end_plan":   ["end plan date", "end plan date(*)", "fecha fin plan"],
    "comments":   ["comments", "comentarios"],
    "workstream": ["workstream", "workstream (*)", "workstream ct"],
    "company":    ["company", "company (*)", "company ct"],
    "task_type":  ["type of task", "type of task (*)", "tipo de tarea", "type of task "],
}

EXCEL_EPOCH = datetime(1899, 12, 30)

# ── Tipos de fila reconocidos ─────────────────────────────────────────────────
SECTION_TYPES = {"section", "sección"}
SUBTASK_TYPES = {"subtask", "subtarea"}
# Anything else (Parent Task, Task, Tarea, etc.) → Parent Task


def parse_date(val):
    if val is None:
        return ""
    if isinstance(val, datetime):
        return val.strftime("%m/%d/%Y")
    try:
        # Excel serial number
        dt = EXCEL_EPOCH + timedelta(days=float(str(val)))
        return dt.strftime("%m/%d/%Y")
    except (ValueError, TypeError):
        return str(val)


def col_letter_to_index(col_str):
    result = 0
    for ch in col_str.upper():
        result = result * 26 + (ord(ch) - ord('A') + 1)
    return result - 1


def parse_cell_ref(ref):
    i = 0
    while i < len(ref) and ref[i].isalpha():
        i += 1
    col = col_letter_to_index(ref[:i])
    row = int(ref[i:]) - 1
    return col, row


def read_xlsx(path):
    with zipfile.ZipFile(path) as z:
        shared_strings = []
        if "xl/sharedStrings.xml" in z.namelist():
            tree = ET.parse(z.open("xl/sharedStrings.xml"))
            for si in tree.getroot().findall(".//{http://schemas.openxmlformats.org/spreadsheetml/2006/main}si"):
                texts = [t.text or "" for t in si.findall(".//{http://schemas.openxmlformats.org/spreadsheetml/2006/main}t")]
                shared_strings.append("".join(texts))
        tree  = ET.parse(z.open("xl/worksheets/sheet1.xml"))
        root  = tree.getroot()
        rows_data = {}
        max_col   = 0
        for row_el in root.findall(".//{http://schemas.openxmlformats.org/spreadsheetml/2006/main}row"):
            r_idx = int(row_el.get("r")) - 1
            cols  = {}
            for c in row_el.findall("{http://schemas.openxmlformats.org/spreadsheetml/2006/main}c"):
                ref  = c.get("r")
                col, _ = parse_cell_ref(ref)
                t    = c.get("t", "n")
                v_el = c.find("{http://schemas.openxmlformats.org/spreadsheetml/2006/main}v")
                val  = None
                if v_el is not None and v_el.text is not None:
                    if t == "s":
                        val = shared_strings[int(v_el.text)]
                    elif t in ("str", "inlineStr", "b"):
                        val = v_el.text
                    else:
                        val = v_el.text
                cols[col] = val
                max_col = max(max_col, col)
            rows_data[r_idx] = cols
        if not rows_data:
            return []
        max_row = max(rows_data.keys())
        result  = []
        for r in range(max_row + 1):
            row = [rows_data.get(r, {}).get(c) for c in range(max_col + 1)]
            result.append(row)
        return result


def detect_header_row(rows):
    """
    Encuentra la fila de cabeceras buscando 'Task Name' (o variantes) en col C.
    Devuelve (header_row_index, data_start_index).
    """
    for i, row in enumerate(rows[:10]):
        for val in row:
            if val and str(val).strip().lower() in [a for aliases in HEADER_ALIASES.values() for a in aliases]:
                # Also verify it looks like a header row (col C has a name-like header)
                c_val = row[2] if len(row) > 2 and row[2] else ""
                if str(c_val).strip().lower() in HEADER_ALIASES["name"]:
                    return i, i + 1
    return None, 7  # fallback: no header found, data at row 8 (index 7)


def build_col_map(header_row):
    """
    Lee la fila de cabecera y devuelve un dict {field_key: col_index}.
    """
    col_map = {}
    if header_row is None:
        # Default column map (original template)
        return {
            "name": 2, "type": 12, "status": 3, "assignee": 4,
            "start_plan": 5, "end_plan": 6, "comments": 8,
            "workstream": 9, "company": 10, "task_type": 11,
        }
    for col_idx, val in enumerate(header_row):
        if not val:
            continue
        normalized = str(val).strip().lower()
        for key, aliases in HEADER_ALIASES.items():
            if normalized in aliases:
                col_map[key] = col_idx
                break
    return col_map


def safe_get(row, idx):
    if idx is None or idx >= len(row):
        return ""
    v = row[idx]
    return str(v).strip() if v else ""


def classify_type(row, type_col):
    t = safe_get(row, type_col)
    t_lower = t.strip().lower()
    if t_lower in SECTION_TYPES:
        return "Section"
    if t_lower in SUBTASK_TYPES:
        return "Subtask"
    return "Parent Task"  # Task, Parent Task, Tarea, etc.


def detect_project_name(rows):
    """Busca la etiqueta 'Project Name' (o similar) y devuelve el valor de la celda C siguiente."""
    for i, row in enumerate(rows[:6]):
        if len(row) > 2 and row[2]:
            label = str(row[2]).strip().lower()
            if "project name" in label:
                if i + 1 < len(rows) and len(rows[i+1]) > 2 and rows[i+1][2]:
                    return str(rows[i+1][2]).strip()
    return ""


def excel_to_asana(input_path, output_path):
    all_rows = read_xlsx(input_path)

    # Detect structure
    header_idx, data_start = detect_header_row(all_rows)
    header_row = all_rows[header_idx] if header_idx is not None else None
    col_map    = build_col_map(header_row)
    data_rows  = all_rows[data_start:]

    # Project name
    project_name = detect_project_name(all_rows)

    records          = []
    current_section  = ""
    last_parent_task = ""

    for row in data_rows:
        name = safe_get(row, col_map.get("name", 2))
        if not name:
            continue

        row_type = classify_type(row, col_map.get("type"))

        if row_type == "Section":
            current_section  = name
            last_parent_task = ""
            continue
        elif row_type == "Parent Task":
            last_parent_task = name

        parent_name = last_parent_task if row_type == "Subtask" else ""

        rec = {col: "" for col in ASANA_COLUMNS}
        rec["Name"]            = name
        rec["Section/Column"]  = current_section
        rec["Assignee"]        = safe_get(row, col_map.get("assignee"))
        rec["Start Date"]      = parse_date(row[col_map["start_plan"]] if "start_plan" in col_map and col_map["start_plan"] < len(row) else None)
        rec["Due Date"]        = parse_date(row[col_map["end_plan"]]   if "end_plan"   in col_map and col_map["end_plan"]   < len(row) else None)
        rec["Start Plan Date"] = rec["Start Date"]
        rec["End Plan Date"]   = rec["Due Date"]
        rec["Notes"]           = safe_get(row, col_map.get("comments"))
        rec["Workstream CT"]   = safe_get(row, col_map.get("workstream"))
        rec["Company CT"]      = safe_get(row, col_map.get("company"))
        rec["Type of Task"]    = safe_get(row, col_map.get("task_type"))
        rec["Status for Task"] = safe_get(row, col_map.get("status"))
        rec["Parent task"]     = parent_name
        rec["Projects"]        = project_name
        records.append(rec)

    with open(output_path, "w", newline="", encoding="utf-8-sig") as f:
        writer = csv.DictWriter(f, fieldnames=ASANA_COLUMNS)
        writer.writeheader()
        writer.writerows(records)

    print(f"✅  {len(records)} filas exportadas → {output_path}")


