def _get_template():
    """Devuelve la plantilla xlsx como bytes (decodificada del base64 embebido)."""
    return base64.b64decode(_TEMPLATE_B64.replace("\n",""))

EXCEL_EPOCH = datetime(1899, 12, 30)

# ── Style indexes from template reference rows (STYLES col k → Excel col k+1) ─
STYLES = {
    # col k → Excel col k+1 (B=2,C=3,…)
    # H=Start Date, I=Due Date (NEW); J=Duration, K=Comments, L=WS, M=Co, N=ToT, O=Type
    "Section":    {1:20,2:21,3:22,4:22,5:23,6:24,7:23,8:24,9:25,10:26,11:75,12:75,13:75,14:86},
    "Parent Task":{1:28,2:29,3:30,4:31,5:32,6:32,7:32,8:32,9:33,10:79,11:81,12:91,13:91,14:86},
    "Subtask":    {1:28,2:34,3:30,4:31,5:32,6:32,7:32,8:32,9:33,10:79,11:81,12:91,13:91,14:86},
}
DATE_NUMFMT_NEW_ID = 166   # dd/mm/yyyy (added to styles)
ROW_OUTLINE = {"Section": "", "Parent Task": "", "Subtask": ' outlineLevel="1"'}

# ── Helpers ────────────────────────────────────────────────────────────────────
def to_serial(dt):
    return (dt - EXCEL_EPOCH).days if dt else None

def parse_date(s):
    if not s: return None
    for fmt in ("%m/%d/%Y", "%Y-%m-%d", "%d/%m/%Y"):
        try: return datetime.strptime(s.strip(), fmt)
        except ValueError: pass
    return None

def col_letter(n):
    s = ""
    while n:
        n, r = divmod(n - 1, 26)
        s = chr(65 + r) + s
    return s

def read_csv(path):
    with open(path, encoding="utf-8-sig", newline="") as f:
        return list(csv.DictReader(f))

def build_task_rows(records):
    sections_seen, section_tasks = [], {}
    for rec in records:
        sec = rec.get("Section/Column","").strip() or "Sin sección"
        if sec not in section_tasks:
            sections_seen.append(sec)
            section_tasks[sec] = []
        section_tasks[sec].append(rec)
    rows, sec_counter = [], 0
    for sec in sections_seen:
        sec_counter += 1
        tasks = section_tasks[sec]
        rows.append({"num":str(sec_counter),"name":sec,"status":"","assignee":"",
                     "start":None,"end":None,"start_date":None,"due_date":None,
                     "comments":"","workstream":"","company":"","task_type":"",
                     "type":"Section","sec_idx":sec_counter-1})
        parent_counter, subtask_counter = 0, {}
        for task in tasks:
            name = task.get("Name","").strip()
            parent = task.get("Parent task","").strip()
            start = parse_date(task.get("Start Plan Date") or task.get("Start Date",""))
            end   = parse_date(task.get("End Plan Date")   or task.get("Due Date",""))
            if parent:
                cnt = subtask_counter.get(parent,0)+1
                subtask_counter[parent] = cnt
                num, rtype = f"{sec_counter}.{parent_counter}.{cnt}", "Subtask"
            else:
                parent_counter += 1
                subtask_counter[name] = 0
                num, rtype = f"{sec_counter}.{parent_counter}", "Parent Task"
            rows.append({"num":num,"name":name,
                         "status":task.get("Status for Task",""),
                         "assignee":task.get("Assignee",""),
                         "start":start,"end":end,
                         "start_date":parse_date(task.get("Start Date","")),
                         "due_date":parse_date(task.get("Due Date","")),
                         "comments":task.get("Notes",""),
                         "workstream":task.get("Workstream CT",""),
                         "company":task.get("Company CT",""),
                         "task_type":task.get("Type of Task",""),
                         "type":rtype,"sec_idx":sec_counter-1})
    return rows

# ── Shared strings ─────────────────────────────────────────────────────────────
def xml_unescape(s):
    return (s.replace("&amp;","&").replace("&lt;","<")
              .replace("&gt;",">").replace("&quot;",'"').replace("&apos;","'"))

def load_shared_strings(xml_bytes):
    """Returns list of strings in order (XML entities unescaped)."""
    strings = []
    for m in re.finditer(r'<si>(.*?)</si>', xml_bytes.decode("utf-8"), re.DOTALL):
        texts = re.findall(r'<t[^>]*>([^<]*)</t>', m.group(1))
        strings.append(xml_unescape("".join(texts)))
    return strings

def save_shared_strings(strings):
    """Build sharedStrings.xml as bytes."""
    parts = ['<?xml version="1.0" encoding="UTF-8" standalone="yes"?>',
             f'<sst xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main"'
             f' count="{len(strings)}" uniqueCount="{len(strings)}">']
    for s in strings:
        escaped = s.replace("&","&amp;").replace("<","&lt;").replace(">","&gt;").replace('"',"&quot;")
        space = ' xml:space="preserve"' if s != s.strip() else ""
        parts.append(f"<si><t{space}>{escaped}</t></si>")
    parts.append("</sst>")
    return "\n".join(parts).encode("utf-8")

def get_or_add(strings, idx_map, value):
    """Return shared string index, adding if necessary."""
    if value not in idx_map:
        idx_map[value] = len(strings)
        strings.append(value)
    return idx_map[value]

# ── Styles ─────────────────────────────────────────────────────────────────────
def modify_styles(xml_bytes):
    """
    Adds: numFmt 166 (mm/dd/yyyy), fill D9D9D9, bold font clone of fontId 10,
    and clones section cellXfs with D9D9D9 fill (+bold for col C).
    Returns (new_xml_bytes, sec_style_map, date_style_map)
    """
    xml = xml_bytes.decode("utf-8")

    # 1. Add numFmt 166 ─────────────────────────────────────────────────────────
    nf_tag = '<numFmt numFmtId="166" formatCode="dd/mm/yyyy"/>'
    if 'numFmtId="166"' not in xml:
        if '<numFmts' in xml:
            # insert after opening <numFmts...>
            xml = re.sub(r'(<numFmts[^>]*>)', r'\1' + nf_tag, xml, count=1)
            # update count
            def inc_count(m): return m.group(0).replace(m.group(1), str(int(m.group(1))+1))
            xml = re.sub(r'<numFmts[^>]*count="(\d+)"', lambda m: m.group(0).replace(
                f'count="{m.group(1)}"', f'count="{int(m.group(1))+1}"'), xml, count=1)
        else:
            xml = xml.replace('<fonts', f'<numFmts count="1">{nf_tag}</numFmts><fonts', 1)

    # 2. Count existing fills ───────────────────────────────────────────────────
    fills_count = int(re.search(r'<fills count="(\d+)"', xml).group(1))
    d9_fill_id  = fills_count   # new fill will be appended at this index

    # Add D9D9D9 fill before </fills>
    d9_fill = ('<fill><patternFill patternType="solid">'
               '<fgColor rgb="FFD9D9D9"/><bgColor indexed="64"/>'
               '</patternFill></fill>')
    xml = xml.replace('</fills>', d9_fill + '</fills>', 1)
    xml = re.sub(r'<fills count="(\d+)"',
                 f'<fills count="{fills_count+1}"', xml, count=1)

    # 3. Count existing fonts, get font 10 ─────────────────────────────────────
    fonts_count  = int(re.search(r'<fonts count="(\d+)"', xml).group(1))
    bold_font_id = fonts_count

    # Extract font at index 10
    font_els = re.findall(r'<font>.*?</font>', xml, re.DOTALL)
    if len(font_els) > 10:
        font10 = font_els[10]
        if '<b/>' not in font10 and '<b ' not in font10:
            bold_font = font10.replace('<font>', '<font><b/>', 1)
        else:
            bold_font = font10
        xml = xml.replace('</fonts>', bold_font + '</fonts>', 1)
        xml = re.sub(r'<fonts count="(\d+)"',
                     f'<fonts count="{fonts_count+1}"', xml, count=1)
    else:
        bold_font_id = 10  # fallback

    # 4. Count existing cellXfs ────────────────────────────────────────────────
    xfs_count = int(re.search(r'<cellXfs count="(\d+)"', xml).group(1))
    all_xfs   = re.findall(r'<xf [^/]*/>', xml) + re.findall(r'<xf .*?</xf>', xml, re.DOTALL)
    # simpler: just find all <xf...> blocks
    all_xfs = re.findall(r'<xf(?:\s[^>]*)?>(?:.*?</xf>|)', xml, re.DOTALL)
    # Actually use a different approach: find by cellXfs block
    cxfs_block = re.search(r'<cellXfs count="\d+">(.*?)</cellXfs>', xml, re.DOTALL)
    xf_list = re.findall(r'<xf(?:\s[^>]*)?>(?:.*?</xf>)?', cxfs_block.group(1), re.DOTALL) if cxfs_block else []

    sec_style_map  = {}
    date_style_map = {}
    new_xfs        = []
    seen_key       = {}

    def clone_xf_with_fill(orig_s, fill_id, font_id=None):
        """Return XML for a cloned cellXf with modified fill, unified border=1 (and optionally font)."""
        if orig_s < len(xf_list):
            xf = xf_list[orig_s]
        else:
            xf = f'<xf numFmtId="0" fontId="0" fillId="{fill_id}" borderId="1" xfId="0"/>'
        xf = re.sub(r'fillId="\d+"', f'fillId="{fill_id}"', xf)
        xf = re.sub(r'applyFill="\d+"', 'applyFill="1"', xf)
        if 'applyFill' not in xf:
            xf = xf.replace('<xf ', '<xf applyFill="1" ', 1)
        # Unify border to borderId=1 (all sides thin)
        xf = re.sub(r'borderId="\d+"', 'borderId="1"', xf)
        xf = re.sub(r'applyBorder="\d+"', 'applyBorder="1"', xf)
        if 'applyBorder' not in xf:
            xf = xf.replace('<xf ', '<xf applyBorder="1" ', 1)
        if font_id is not None:
            xf = re.sub(r'fontId="\d+"', f'fontId="{font_id}"', xf)
            xf = re.sub(r'applyFont="\d+"', 'applyFont="1"', xf)
            if 'applyFont' not in xf:
                xf = xf.replace('<xf ', '<xf applyFont="1" ', 1)
        return xf

    def clone_xf_with_date(orig_s):
        """Return XML for a cloned cellXf with numFmtId 166."""
        if orig_s < len(xf_list):
            xf = xf_list[orig_s]
        else:
            xf = f'<xf numFmtId="{DATE_NUMFMT_NEW_ID}" fontId="0" fillId="0" borderId="0" xfId="0"/>'
        xf = re.sub(r'numFmtId="\d+"', f'numFmtId="{DATE_NUMFMT_NEW_ID}"', xf)
        xf = re.sub(r'applyNumberFormat="\d+"', 'applyNumberFormat="1"', xf)
        if 'applyNumberFormat' not in xf:
            xf = xf.replace('<xf ', '<xf applyNumberFormat="1" ', 1)
        return xf

    # Build section styles
    new_xf_xml = ""
    next_idx = xfs_count
    for col, orig_s in STYLES["Section"].items():
        use_bold = (col == 2)
        key = (orig_s, use_bold)
        if key not in seen_key:
            font_id = bold_font_id if use_bold else None
            xf_xml  = clone_xf_with_fill(orig_s, d9_fill_id, font_id)
            new_xf_xml += xf_xml
            seen_key[key] = next_idx
            next_idx += 1
        sec_style_map[col] = seen_key[key]

    # Build date styles for parent/subtask
    for rt in ("Parent Task", "Subtask"):
        for col in (5, 6):
            orig_s = STYLES[rt][col]
            if orig_s not in date_style_map:
                xf_xml = clone_xf_with_date(orig_s)
                new_xf_xml += xf_xml
                date_style_map[orig_s] = next_idx
                next_idx += 1

    xml = xml.replace('</cellXfs>', new_xf_xml + '</cellXfs>', 1)
    xml = re.sub(r'<cellXfs count="(\d+)"',
                 f'<cellXfs count="{next_idx}"', xml, count=1)

    # Clone style 8 (E3/E5 date cells) with numFmtId 166
    e3e5_style_idx = next_idx
    xf8 = clone_xf_with_date(8)
    new_xf_xml2 = xf8
    xml = xml.replace('</cellXfs>', new_xf_xml2 + '</cellXfs>', 1)
    xml = re.sub(r'<cellXfs count="(\d+)"',
                 f'<cellXfs count="{next_idx+1}"', xml, count=1)

    return xml.encode("utf-8"), sec_style_map, date_style_map, e3e5_style_idx

# ── Sheet XML ──────────────────────────────────────────────────────────────────
def make_cell_xml(xl_r, col_xl, s, value=None, t=None, formula=None):
    ref = f"{col_letter(col_xl)}{xl_r}"
    if formula:
        return f'<c r="{ref}" s="{s}"><f>{formula}</f></c>'
    if value is None:
        return f'<c r="{ref}" s="{s}"/>'
    t_attr = f' t="{t}"' if t else ""
    return f'<c r="{ref}" s="{s}"{t_attr}><v>{value}</v></c>'

def build_rows_xml(task_rows, sec_style_map, date_style_map, strings, idx_map):
    parts = []
    DYDES = 'x14ac:dyDescent="0.25"'
    for i, row in enumerate(task_rows):
        xl_r     = 8 + i
        rtype    = row["type"]
        outline  = ROW_OUTLINE[rtype]
        smap     = sec_style_map if rtype == "Section" else STYLES[rtype]

        def S(k, d=0): return str(smap.get(k, d))
        def ss(val):   return str(get_or_add(strings, idx_map, val))

        cells = f'<c r="A{xl_r}" s="19"/>'

        # B(2): task number
        cells += make_cell_xml(xl_r, 2, S(1,20), ss(row["num"]), t="s")
        # C(3): name
        cells += make_cell_xml(xl_r, 3, S(2,21), ss(row["name"]), t="s")

        if rtype != "Section":
            # D(4) status
            cells += make_cell_xml(xl_r,4, S(3,30), ss(row["status"]) if row["status"] else None,
                                   t="s" if row["status"] else None)
            # E(5) assignee
            cells += make_cell_xml(xl_r,5, S(4,31), ss(row["assignee"]) if row["assignee"] else None,
                                   t="s" if row["assignee"] else None)
            # F(6) start plan date
            fs = str(date_style_map.get(STYLES[rtype][5], STYLES[rtype][5]))
            cells += make_cell_xml(xl_r,6, fs, str(to_serial(row["start"])) if row["start"] else None)
            # G(7) end plan date
            es = str(date_style_map.get(STYLES[rtype][6], STYLES[rtype][6]))
            cells += make_cell_xml(xl_r,7, es, str(to_serial(row["end"])) if row["end"] else None)
            # H(8) start date (NEW)
            hds = str(date_style_map.get(STYLES[rtype][7], STYLES[rtype][7]))
            cells += make_cell_xml(xl_r,8, hds, str(to_serial(row["start_date"])) if row["start_date"] else None)
            # I(9) due date (NEW)
            ids = str(date_style_map.get(STYLES[rtype][8], STYLES[rtype][8]))
            cells += make_cell_xml(xl_r,9, ids, str(to_serial(row["due_date"])) if row["due_date"] else None)
            # J(10) duration
            if row["start"] and row["end"]:
                cells += make_cell_xml(xl_r,10, S(9,33),
                                       formula=f"IF(AND(F{xl_r}&gt;0,G{xl_r}&gt;0),G{xl_r}-F{xl_r},0)")
            else:
                cells += make_cell_xml(xl_r,10, S(9,33))
            # K(11) comments
            cells += make_cell_xml(xl_r,11,S(10,79), ss(row["comments"]) if row["comments"] else None,
                                   t="s" if row["comments"] else None)
            # L(12) workstream
            cells += make_cell_xml(xl_r,12,S(11,81), ss(row["workstream"]) if row["workstream"] else None,
                                   t="s" if row["workstream"] else None)
            # M(13) company
            cells += make_cell_xml(xl_r,13,S(12,91),ss(row["company"]) if row["company"] else None,
                                   t="s" if row["company"] else None)
            # N(14) type of task
            cells += make_cell_xml(xl_r,14,S(13,91),ss(row["task_type"]) if row["task_type"] else None,
                                   t="s" if row["task_type"] else None)
            # O(15) type (hidden)
            cells += make_cell_xml(xl_r,15,S(14,86), ss(row["type"]), t="s")
        else:
            for col_xl,d_s in [(4,22),(5,22),(6,23),(7,24),(8,23),(9,24),(10,25),(11,26),(12,75),(13,75),(14,75),(15,86)]:
                cells += f'<c r="{col_letter(col_xl)}{xl_r}" s="{S(col_xl-1,d_s)}"/>'

        parts.append(
            f'<row r="{xl_r}" spans="1:13" s="27" customFormat="1"'
            f' ht="24.95" customHeight="1"{outline} {DYDES}>'
            + cells + '</row>')
    return "".join(parts)

def modify_sheet(xml_bytes, task_rows, project_name, proj_start, proj_end,
                 sec_style_map, date_style_map, strings, idx_map, e3e5_style=8):
    xml = xml_bytes.decode("utf-8")

    # Update C3 (project name)
    if project_name:
        proj_idx = str(get_or_add(strings, idx_map, project_name))
        xml = re.sub(r'(<c r="C3"[^>]*t="s"><v>)\d+(</v></c>)',
                     rf'\g<1>{proj_idx}\2', xml)

    # Clear C4 (Owner label - not needed in output)
    xml = xml.replace('<c r="C4" s="9" t="s"><v>6</v></c>', '<c r="C4" s="9"/>')
    xml = xml.replace('<c r="C5" s="10"/>', '<c r="C5" s="1"/>')

    # Update E3/E5 with new date style (mm/dd/yyyy)
    if proj_start:
        serial = str(to_serial(proj_start))
        xml = re.sub(r'<c r="E3" s="[0-9]+"><v>[0-9]+</v></c>',
                     f'<c r="E3" s="{e3e5_style}"><v>{serial}</v></c>', xml)
    if proj_end:
        serial = str(to_serial(proj_end))
        xml = re.sub(r'<c r="E5" s="[0-9]+"><v>[0-9]+</v></c>',
                     f'<c r="E5" s="{e3e5_style}"><v>{serial}</v></c>', xml)

    # Update row 7 headers: add Start Date (H7), Due Date (I7); shift J-O
    # Style 14 = header style (same as original H7/I7)
    hdr_style = "14"
    hdr92     = "92"  # style for Type of Task / Type headers
    def get_ss_idx(name):
        return str(get_or_add(strings, idx_map, name))
    # H7 = Start Date, I7 = Due Date
    xml = re.sub(r'<c r="H7" s="\d+" t="s"><v>\d+</v></c>',
                 f'<c r="H7" s="{hdr_style}" t="s"><v>{get_ss_idx("Start Date")}</v></c>', xml)
    xml = re.sub(r'<c r="I7" s="\d+" t="s"><v>\d+</v></c>',
                 f'<c r="I7" s="{hdr_style}" t="s"><v>{get_ss_idx("Due Date")}</v></c>', xml)
    # J7 = DURATION (days)
    xml = re.sub(r'<c r="J7" s="\d+" t="s"><v>\d+</v></c>',
                 f'<c r="J7" s="{hdr_style}" t="s"><v>{get_ss_idx("DURATION (days)")}</v></c>', xml)
    # K7 = Comments
    xml = re.sub(r'<c r="K7" s="\d+" t="s"><v>\d+</v></c>',
                 f'<c r="K7" s="{hdr_style}" t="s"><v>{get_ss_idx("Comments")}</v></c>', xml)
    # L7 = Workstream
    xml = re.sub(r'<c r="L7" s="\d+" t="s"><v>\d+</v></c>',
                 f'<c r="L7" s="{hdr_style}" t="s"><v>{get_ss_idx("Workstream")}</v></c>', xml)
    # M7 = Company
    xml = re.sub(r'<c r="M7" s="\d+" t="s"><v>\d+</v></c>',
                 f'<c r="M7" s="{hdr_style}" t="s"><v>{get_ss_idx("Company")}</v></c>', xml)
    # N7 = Type of Task (was empty cell in template)
    xml = xml.replace('<c r="N7" s="1"/>',
                      f'<c r="N7" s="{hdr92}" t="s"><v>{get_ss_idx("Type of Task")}</v></c>')
    # O7 = Type
    xml = re.sub(r'<c r="O7" s="\d+" t="s"><v>\d+</v></c>',
                 f'<c r="O7" s="{hdr92}" t="s"><v>{get_ss_idx("Type")}</v></c>', xml)

    # Remove conditionalFormatting (overrides section fill colors)
    xml = re.sub(r'<conditionalFormatting[^>]*>.*?</conditionalFormatting>', '', xml, flags=re.DOTALL)

    # Hide columns O-S (min/max 15-19): add hidden="1" to overlapping col entries
    def hide_col(m):
        tag = m.group(0)
        mn, mx = int(m.group(1)), int(m.group(2))
        if mx >= 15 and mn <= 19:
            if 'hidden' not in tag:
                tag = tag.replace('/>', ' hidden="1"/>')
        return tag
    xml = re.sub(r'<col min="(\d+)" max="(\d+)"[^/]*/>', hide_col, xml)

    # Replace data rows (row 8+) inside <sheetData>
    new_rows = build_rows_xml(task_rows, sec_style_map, date_style_map, strings, idx_map)

    # Find the first <row r="8" and </sheetData>
    m8 = re.search(r'<row r="8"[ >]', xml)
    sd_end = xml.rfind('</sheetData>')
    if m8 and sd_end > 0:
        xml = xml[:m8.start()] + new_rows + xml[sd_end:]
    elif sd_end > 0:
        # No row 8 yet, insert before </sheetData>
        xml = xml[:sd_end] + new_rows + xml[sd_end:]

    return xml.encode("utf-8")

# ── Shared strings update ──────────────────────────────────────────────────────
def update_shared_strings(orig_xml_bytes, strings):
    """Rebuild sharedStrings.xml with full updated string list."""
    return save_shared_strings(strings)

# ── Main conversion ────────────────────────────────────────────────────────────
# Plantilla embebida como base64 (autónomo, no requiere fichero externo)
_TEMPLATE_B64 = """"""

def asana_to_excel(input_csv, output_xlsx):
    records   = read_csv(input_csv)
    task_rows = build_task_rows(records)
    project_name = records[0].get("Projects","") if records else ""
    all_starts = [r["start"] for r in task_rows if r["start"] and r["type"]!="Section"]
    all_ends   = [r["end"]   for r in task_rows if r["end"]   and r["type"]!="Section"]
    proj_start = min(all_starts) if all_starts else None
    proj_end   = max(all_ends)   if all_ends   else None

    # Load template from embedded base64
    template_bytes = _get_template()
    with zipfile.ZipFile(io.BytesIO(template_bytes)) as z:
        all_files   = {n: z.read(n) for n in z.namelist()}

    # Load shared strings
    ss_xml  = all_files.get("xl/sharedStrings.xml", b"")
    strings = load_shared_strings(ss_xml)
    idx_map = {s: i for i, s in enumerate(strings)}

    # Modify styles
    new_styles, sec_style_map, date_style_map, e3e5_style = modify_styles(all_files["xl/styles.xml"])

    # Modify sheet
    new_sheet = modify_sheet(all_files["xl/worksheets/sheet1.xml"],
                             task_rows, project_name, proj_start, proj_end,
                             sec_style_map, date_style_map, strings, idx_map,
                             e3e5_style)

    # Rebuild shared strings
    new_ss = update_shared_strings(ss_xml, strings)

    # Update sheet tab name in workbook.xml
    wb_xml = all_files.get("xl/workbook.xml", b"").decode("utf-8")
    if project_name and wb_xml:
        safe_name = project_name[:31].replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;").replace('"', "&quot;")
        wb_xml = re.sub(r'(<sheet [^>]*name=")[^"]*(")', rf'\g<1>{safe_name}\2', wb_xml, count=1)
        all_files["xl/workbook.xml"] = wb_xml.encode("utf-8")

    # Remove chart/drawing files from all_files entirely
    all_files = {k: v for k, v in all_files.items()
                 if not any(x in k for x in ('xl/charts/', 'xl/drawings/'))}

    # Remove chart references from sheet1.xml.rels
    rels_key = 'xl/worksheets/_rels/sheet1.xml.rels'
    if rels_key in all_files:
        rels_xml = all_files[rels_key].decode('utf-8')
        import re as _re
        rels_xml = _re.sub(r'<Relationship[^>]*(?:chart|drawing)[^>]*/>', '', rels_xml)
        all_files[rels_key] = rels_xml.encode('utf-8')

    # Remove drawing anchor from sheet1.xml
    new_sheet = re.sub(rb'<drawing[^/]*/>', b'', new_sheet)

    # Remove chart/drawing from Content_Types
    ct_key = '[Content_Types].xml'
    if ct_key in all_files:
        ct_xml = all_files[ct_key].decode('utf-8')
        ct_xml = re.sub(r'<Override[^>]*(?:chart|drawing)[^>]*/>', '', ct_xml)
        all_files[ct_key] = ct_xml.encode('utf-8')

    # Write output
    with zipfile.ZipFile(output_xlsx, "w", zipfile.ZIP_DEFLATED) as zout:
        for name, data in all_files.items():
            if name == "xl/worksheets/sheet1.xml":
                zout.writestr(name, new_sheet)
            elif name == "xl/styles.xml":
                zout.writestr(name, new_styles)
            elif name == "xl/sharedStrings.xml":
                zout.writestr(name, new_ss)
            elif name == "xl/calcChain.xml":
                pass  # Excel lo reconstruye automáticamente
            else:
                zout.writestr(name, data)

    print(f"✅  {len(task_rows)} filas exportadas → {output_xlsx}")


