"""
Interfaz web para conversión de plantillas de proyecto ↔ Asana
Uso: python app.py
Luego abre http://localhost:5000 en tu navegador
"""

import os, sys, tempfile


app = Flask(__name__)
app.config["MAX_CONTENT_LENGTH"] = 20 * 1024 * 1024  # 20 MB

